import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions, usePersonOptions } from 'features/shared/selectOptionHelpers';

export default function OwnershipsPage() {
  const parcelOptions = useParcelOptions();
  const personOptions = usePersonOptions();

  return (
    <CrudResourceModule
      title="Propietarios / Copropietarios"
      path={API_PATHS.ownerships}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'persona', label: 'Persona', render: (row) => row.persona?.nombre_completo || '-' },
        {
          key: 'tipo',
          label: 'Tipo',
          render: (row) => <Chip size="small" label={row.tipo} color={row.tipo === 'PRINCIPAL' ? 'primary' : 'default'} />
        },
        {
          key: 'is_active',
          label: 'Activo',
          render: (row) => <Chip size="small" label={row.is_active ? 'Sí' : 'No'} color={row.is_active ? 'success' : 'default'} />
        }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        { name: 'persona_id', label: 'Persona', type: 'select', required: true, options: personOptions },
        {
          name: 'tipo',
          label: 'Tipo',
          type: 'select',
          required: true,
          options: [
            { value: 'PRINCIPAL', label: 'Propietario principal' },
            { value: 'COPROPIETARIO', label: 'Copropietario' }
          ]
        },
        { name: 'is_active', label: 'Activo', type: 'checkbox', defaultValue: true },
        { name: 'fecha_inicio', label: 'Fecha inicio', type: 'date' },
        { name: 'fecha_fin', label: 'Fecha fin', type: 'date' },
        { name: 'notas', label: 'Notas', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-created_at"
      searchPlaceholder="Buscar por parcela o persona"
    />
  );
}
